#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        double p[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%lf", &p[i][j]);
            }
        }
        double prob = 1.0;
        for (int j = 0; j < M; j++) {
            prob *= p[0][j];
        }
        double sum = prob;
        double q = 1 - prob;
        for (int i = 1; i < 100; i++) {
            sum += prob * pow(q, i);
        }
        printf("%.6f\n", sum);
    }
    return 0;
}

