    let [N, M] = nextLine().split(' ').map(Number);
    let p = [];
    for (let i = 0; i < N; i++) {
        p.push(nextLine().split(' ').map(Number));
    }
    let prob = 1.0;
    for (let j = 0; j < M; j++) {
        prob *= p[0][j];
    }
    let sum = prob;
    let q = 1 - prob;
    for (let i = 1; i < 100; i++) {
        sum += prob * Math.pow(q, i);
    }
    console.log(sum.toFixed(6));
}

